    ("exam", "补充策略", "错题管理进阶技巧209", "这是关于错题管理的高级应用技巧。掌握这些技巧可以帮助你在考场上更加从容应对各种题型。需要通过大量练习才能熟练掌握。", "medium", "不重视错题管理的细节", "在日常练习中有意识地运用这些技巧。", "通过模拟考试检验效果", ["错题管理", "备考策略"], 499),
    ("exam", "补充策略", "信息搜集进阶技巧210", "这是关于信息搜集的高级应用技巧。掌握这些技巧可以帮助你在考场上更加从容应对各种题型。需要通过大量练习才能熟练掌握。", "medium", "不重视信息搜集的细节", "在日常练习中有意识地运用这些技巧。", "通过模拟考试检验效果", ["信息搜集", "备考策略"], 500),
    ("mental", "压力管理", "考研压力管理的4个层次", "第一层：识别压力源。第二层：针对性解决。第三层：建立支持系统。第四层：心理调适技巧。", "high", "压抑压力不处理", "找到自己的压力源。建立支持网络。", "每周做一次压力自评", ["压力管理", "心态"], 501),
    ("mental", "焦虑应对", "考研焦虑是正常的生理反应", "适度焦虑有助于提高学习效率。但过度焦虑会影响睡眠和注意力。", "high", "认为焦虑是软弱的表现", "学习识别焦虑信号。掌握呼吸放松技巧。", "记录焦虑出现的频率和强度", ["焦虑应对", "心态"], 502),
    ("mental", "心态调整", "不要和别人比进度", "每个人的起点和学习能力不同。比较进度只会增加焦虑。", "high", "频繁和同学比较", "制定适合自己的学习计划。", "记录自己的学习成果", ["心态调整", "心态"], 503),
    ("mental", "心态调整", "考研不是人生的全部", "考研只是人生众多选择中的一个。即使失败，人生还有很多可能。", "high", "认为考研失败就是人生失败", "保持其他的人生选项。", "每月做一次全面评估", ["心态调整", "心态"], 504),
    ("mental", "社交维护", "备考期间不要完全切断社交", "适度社交有助于缓解压力。但要控制社交时间。", "medium", "完全断绝社交", "每周安排1-2次简短社交活动。", "记录社交时间和感受", ["社交维护", "心态"], 505),
    ("mental", "睡眠管理", "睡眠质量直接影响学习效率", "睡眠不足严重影响记忆力和注意力。建议每天7-8小时。", "high", "熬夜学习", "制定固定的作息时间。", "记录睡眠时间和质量", ["睡眠管理", "心态"], 506),
    ("mental", "身体管理", "运动是最高效的减压方式", "每天30分钟中等强度运动可以显著改善情绪和学习效率。", "medium", "备考期间不运动", "每天安排30分钟运动时间。", "记录运动频率和感受", ["身体管理", "心态"], 507),
    ("mental", "情绪管理", "允许自己有情绪低落的时候", "长期高强度备考必然会有情绪波动。偶尔低落是正常的。", "medium", "要求自己时刻保持积极", "接受情绪波动是正常的。", "记录情绪变化的规律", ["情绪管理", "心态"], 508),
    ("mental", "学习节奏", "番茄工作法适合考研备考", "25分钟专注学习+5分钟休息。每4个番茄钟休息20分钟。", "medium", "连续学习不休息", "尝试番茄工作法。", "记录每个番茄钟的学习效果", ["学习节奏", "心态"], 509),
    ("mental", "目标管理", "把大目标分解成小任务", "把最终目标分解成每周的学习任务。完成小任务会带来成就感。", "high", "只盯着最终目标", "制定月计划、周计划、日计划。", "每天记录完成的任务", ["目标管理", "心态"], 510),
    ("mental", "学习环境", "学习环境影响学习效率", "图书馆、自习室比宿舍学习效率高。减少手机干扰。", "medium", "在宿舍学习", "固定一个高效的学习场所。", "对比不同环境的学习效率", ["学习环境", "心态"], 511),
    ("mental", "积极心理", "自我暗示可以增强信心", "积极的自我暗示可以改善心态和表现。每天对自己说几句鼓励的话。", "medium", "消极自我暗示", "每天进行积极的自我对话。", "记录积极自我暗示的效果", ["积极心理", "心态"], 512),
    ("mental", "压力释放", "找到适合自己的减压方式", "音乐、运动、倾诉、写日记都是有效的减压方式。", "medium", "不主动减压", "尝试不同的减压方式。", "记录不同减压方式的效果", ["压力释放", "心态"], 513),
    ("mental", "时间焦虑", "感觉时间不够用是正常的", "关键是高效利用时间，而不是焦虑时间不够。专注于当下的学习任务。", "high", "一直焦虑时间不够", "制定详细的时间计划。", "记录每天的有效学习时间", ["时间焦虑", "心态"], 514),
