def seed_grad_intel(db: Session) -> int:
    count = 0
    seen = set()
    for data in GRAD_INTEL:
        key = (data[0], data[1])
        if key in seen:
            continue
        seen.add(key)
        existing = db.query(GradSchoolIntel).filter(
            GradSchoolIntel.school_name == data[0],
            GradSchoolIntel.major_name == data[1],
        ).first()
        if existing:
            continue
        intel = GradSchoolIntel(
            user_id=SYSTEM_USER_ID,            school_name=data[0], major_name=data[1], school_tier=data[2],
            year=data[3], background_discrimination=data[4],
            first_choice_protection=data[5], admission_ratio=data[6],
            push_ratio=data[7], actual_quota=data[8], score_line=data[9],
            retest_weight=data[10], retest_format=data[11],
            score_suppression=data[12], transfer_friendly=data[13],
            )
        db.add(intel)
        count += 1
    db.commit()
    return count


def seed_dark_knowledge(db: Session) -> int:
    count = 0
    seen_titles = set()
    for data in DARK_KNOWLEDGE:
        if data[2] in seen_titles:
            continue
        seen_titles.add(data[2])
        existing = db.query(DarkKnowledge).filter(DarkKnowledge.title == data[2]).first()
        if existing:
            continue
        dk = DarkKnowledge(
            stage=data[0], category=data[1], title=data[2],
            content=data[3], importance=data[4],
            common_misconception=data[5], actionable_advice=data[6],
            verification_method=data[7], tags=data[8], sort_order=data[9],
            )
        db.add(dk)
        count += 1
    db.commit()
    return count
